#include<bits/stdc++.h>
using namespace std;
const int N = 3e6+5;
struct line{int v,w;};
vector<line> g[N];queue<int> q;
int n,m,a[105],mn,dis[N],ans;bool is[N];
int main(){
    cin>>n>>m;mn=0x3f3f3f3f;
    for(int i=1;i<=n;i++)cin>>a[i];sort(a+1,a+n+1);
    mn=max(1,a[1]-m);if(mn==1){cout<<"-1\n";return 0;}
    for(int i=1;i<=n;i++)for(int j=max(a[i-1]+1,a[i]-m);j<=a[i];j++)
        if(j!=mn)for(int k=0;k<mn;k++)g[k].push_back({(k+j)%mn,j});
    memset(dis,0x3f,sizeof(dis));dis[0]=0;q.push(0);
    while(!q.empty()){
        int u=q.front();q.pop();is[u]=0;
        for(auto [v,w]:g[u])if(dis[v]>dis[u]+w)
            {dis[v]=dis[u]+w;if(!is[v])is[v]=1,q.push(v);}
    }
    for(int i=1;i<mn;i++)if(dis[i]>1e8){cout<<"-1\n";return 0;}
    for(int i=1;i<mn;i++)ans=max(ans,dis[i]-mn);cout<<ans<<"\n";
    return 0;
}
